@app.route("/introspect", methods=["POST"])
def introspect():
    token = request.form.get("token", "")
    info = access_tokens.get(token)
    if not info:
        return jsonify({"active": False})
    return jsonify({
        "active": True,
        "user_id": info["user_id"],
        "client_id": info["client_id"],
        "scope": info["scope"],
        "issued_at": info["issued_at"],
    })

